const templates = $input.all().map(i => i.json);
if (!templates.length || (templates.length === 1 && !templates[0].id)) {
  throw new Error('No templates found for template_set_id: ' +
    $('Get Wave').first().json.template_set_id);
}
return templates.map(t => ({ json: t }));

// Collect all wave_lead IDs for idempotent queue cleanup
const items = $input.all().map(i => i.json);
const ids = items.filter(i => i.id).map(i => i.id);
if (!ids.length) return [{ json: { wl_ids: '' } }];
return [{ json: { wl_ids: ids.join(',') } }];

function renderTemplate(text, vars) {
  return (text || '').replace(/\{\{(\w+)\}\}/g, (_, key) =>
    vars[key] !== undefined && vars[key] !== '' ? vars[key] : '{{' + key + '}}'
  );
}

function isValidMinute(m) { return (m % 5) !== 0; }
function advanceToValidMinute(date) {
  while (!isValidMinute(date.getMinutes())) date.setMinutes(date.getMinutes() + 1);
  return date;
}
function randomDelay() { return 4 + Math.floor(Math.random() * 5); }

function getCzechOffset(dateStr) {
  const year = parseInt(dateStr.split('-')[0]);
  let d = new Date(Date.UTC(year, 2, 31));
  while (d.getUTCDay() !== 0) d.setUTCDate(d.getUTCDate() - 1);
  const dstStart = Date.UTC(year, 2, d.getUTCDate(), 1, 0);
  d = new Date(Date.UTC(year, 9, 31));
  while (d.getUTCDay() !== 0) d.setUTCDate(d.getUTCDate() - 1);
  const dstEnd = Date.UTC(year, 9, d.getUTCDate(), 1, 0);
  const check = new Date(dateStr + 'T12:00:00Z').getTime();
  return (check >= dstStart && check < dstEnd) ? 2 : 1;
}

const wave = $('Get Wave').first().json;
if (!wave || !wave.id) throw new Error('Wave not found');

// Fix 1: Double-scheduling guard
if (['scheduled', 'sending', 'done', 'completed'].includes(wave.status)) {
  throw new Error('Wave already in status: ' + wave.status);
}

const isDummy = wave.is_dummy === true;
const dummyEmail = wave.dummy_email || '';
const fromEmail = wave.from_email || '';
if (!fromEmail) throw new Error('No FROM email set on wave');

const templates = $('Validate Templates').all().map(i => i.json);
const waveLeadsRaw = $('Get Wave Leads').all().map(i => i.json);
const seenWL = new Set();
const waveLeads = waveLeadsRaw.filter(wl => { if (seenWL.has(wl.id)) return false; seenWL.add(wl.id); return true; });

if (!waveLeads.length) throw new Error('No wave leads found');

// Get distinct sorted sequence numbers from actual templates (not hardcoded 1,2,3)
const seqNumbers = [...new Set(templates.map(t => t.sequence_number))].sort((a, b) => a - b);
if (!seqNumbers.length) throw new Error('No sequence numbers found in templates');

// Map sequence position (0-based index in seqNumbers) to DB column (send_date_seq1/2/3)
function getSeqDateAndTime(seqIndex) {
  const fallbackTime = wave.send_window_start || '08:00';
  const colIndex = seqIndex + 1; // 1-based for column names
  if (colIndex === 1) {
    return {
      date: wave.send_date_seq1 || new Date().toISOString().slice(0, 10),
      time: wave.send_time_seq1 || fallbackTime,
    };
  }
  if (colIndex === 2) {
    if (wave.send_date_seq2) return { date: wave.send_date_seq2, time: wave.send_time_seq2 || '08:00' };
    const seq1Info = getSeqDateAndTime(0);
    const base = new Date(seq1Info.date);
    base.setDate(base.getDate() + (wave.delay_seq1_to_seq2_days || 3));
    return { date: base.toISOString().slice(0, 10), time: fallbackTime };
  }
  // colIndex === 3
  if (wave.send_date_seq3) return { date: wave.send_date_seq3, time: wave.send_time_seq3 || '08:00' };
  const seq2Info = getSeqDateAndTime(1);
  const base = new Date(seq2Info.date);
  base.setDate(base.getDate() + (wave.delay_seq2_to_seq3_days || 5));
  return { date: base.toISOString().slice(0, 10), time: fallbackTime };
}

const seqPointers = {};
function getNextScheduledTime(seq, seqIndex) {
  if (!seqPointers[seq]) {
    if (isDummy) {
      const d = new Date();
      d.setMinutes(d.getMinutes() + seqIndex * 2);
      seqPointers[seq] = d;
    } else {
      const { date, time } = getSeqDateAndTime(seqIndex);
      const [h, m] = (time || '08:00').split(':').map(Number);
      const offset = getCzechOffset(date);
      const pad2 = n => String(n).padStart(2, '0');
      const d = new Date(`${date}T${pad2(h)}:${pad2(m)}:00+${pad2(offset)}:00`);
      advanceToValidMinute(d);
      seqPointers[seq] = d;
    }
  }
  const scheduledTime = new Date(seqPointers[seq]);
  if (!isDummy) {
    seqPointers[seq].setMinutes(seqPointers[seq].getMinutes() + randomDelay());
    advanceToValidMinute(seqPointers[seq]);
  } else {
    seqPointers[seq].setSeconds(seqPointers[seq].getSeconds() + 10);
  }
  return scheduledTime;
}

function mapEmailType(candidateType) {
  if (candidateType === 'staff' || candidateType === 'staff_decision_maker') return 'staff';
  if (candidateType === 'generic') return 'generic';
  return 'jednatel';
}

function pickTemplate(tmpls, seq, variant, emailType) {
  return tmpls.find(t => t.sequence_number === seq && t.variant === variant && t.email_type === emailType)
    || tmpls.find(t => t.sequence_number === seq && t.variant === variant && t.email_type === 'jednatel')
    || tmpls.find(t => t.sequence_number === seq && t.variant === variant)
    || tmpls.find(t => t.sequence_number === seq);
}

const queueItems = [];
const skipped = [];
const wlUpdates  = [];

for (const wl of waveLeads) {
  const lead = wl.leads || {};
  const contactsRaw = lead.companies?.contacts;
  if (!contactsRaw) continue;
  const contacts = Array.isArray(contactsRaw) ? contactsRaw : [contactsRaw];

  const candidateMap = new Map();
  for (const j of contacts) {
    const cands = Array.isArray(j.email_candidates) ? j.email_candidates : [];
    for (const c of cands) {
      const isUsable = isDummy || c.is_verified || c.qev_status === 'valid' || c.seznam_status === 'likely_valid';
      if (!isUsable) continue;
      if (!candidateMap.has(c.email_address)) {
        candidateMap.set(c.email_address, { email: c.email_address, type: c.type || 'jednatel', jednatel: j });
      }
    }
  }

  if (!candidateMap.size && isDummy && contacts.length > 0) {
    const j = contacts[0];
    candidateMap.set(dummyEmail, { email: dummyEmail, type: 'jednatel', jednatel: j });
  }
  if (!candidateMap.size) { skipped.push({ lead_id: wl.lead_id, company_name: lead.company_name || '(unknown)', reason: 'no_verified_email' }); continue; }

  const abVariant = Math.random() < 0.5 ? 'A' : 'B';
  wlUpdates.push({ id: wl.id, ab_variant: abVariant });

  const customFields = lead.custom_fields || {};

  for (const { email: verifiedEmail, type: candType, jednatel: selectedJ } of candidateMap.values()) {
    const emailType = mapEmailType(candType);
    const standardVars = {
      salutation:   selectedJ.salutation  || '',
      company_name: lead.company_name     || '',
      first_name:   selectedJ.first_name  || '',
      last_name:    selectedJ.last_name   || '',
      full_name:    selectedJ.full_name   || '',
      ico:          lead.ico              || '',
      domain:       lead.domain           || '',
    };
    const vars = { ...standardVars, ...customFields };

      // Compute seq 1's rendered subject for email threading (all seqs share this)
      const seq1Tpl = pickTemplate(templates, seqNumbers[0], abVariant, emailType);
      const threadSubject = (isDummy ? '[TEST] ' : '') + renderTemplate(seq1Tpl ? seq1Tpl.subject : '', vars);

    // Iterate actual template sequence numbers (not hardcoded 1..3)
    for (let i = 0; i < seqNumbers.length; i++) {
      const seq = seqNumbers[i];
      const tpl = pickTemplate(templates, seq, abVariant, emailType);
      if (!tpl) continue;

      const scheduledAt = getNextScheduledTime(seq, i);

      queueItems.push({
        wave_lead_id:        wl.id,
        jednatel_id:         selectedJ.id,
        email_address:       isDummy && dummyEmail ? dummyEmail : verifiedEmail,
        sequence_number:     seq,
        subject_rendered:    (isDummy ? '[TEST] ' : '') + renderTemplate(tpl.subject, vars),
        body_rendered:       renderTemplate(tpl.body_html, vars),
          thread_subject:      threadSubject,
        status:              i === 0 ? 'queued' : 'pending_prev',
        max_sequence_number: seqNumbers[seqNumbers.length - 1],
        retry_count:         0,
        scheduled_at:        scheduledAt.toISOString(),
      });
    }
  }
}

if (!queueItems.length && isDummy) throw new Error('No queue items generated - add at least one lead with a jednatel');
if (!queueItems.length) throw new Error('No queue items generated - no leads with verified emails');

// Build wave date update to write computed dates back to waves table
const waveDateUpdate = { wave_id: wave.id };
for (let i = 0; i < Math.min(seqNumbers.length, 3); i++) {
  const info = getSeqDateAndTime(i);
  const col = i + 1;
  waveDateUpdate['send_date_seq' + col] = info.date;
  waveDateUpdate['send_time_seq' + col] = info.time;
}

const schedulingReport = { queued: queueItems.length, skipped: skipped.length, skipped_leads: skipped };

return [
  { json: { _type: 'wave_date_update', ...waveDateUpdate, scheduling_report: schedulingReport } },
  ...wlUpdates.map(u => ({ json: { _type: 'wavelead_update', ...u } })),
  ...queueItems.map(q => ({ json: { _type: 'queue_item',     ...q } })),
];
